"use client";
// Mirrors React-template ContactForm.jsx

import { useState } from "react";

export default function ContactForm() {
  const [sent, setSent] = useState(false);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSent(true);
    setTimeout(() => setSent(false), 4000);
  }

  return (
    <form className="contact-form" onSubmit={handleSubmit}>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-0">
        <div className="cf-field">
          <label htmlFor="cf-name">Your Name</label>
          <input id="cf-name" type="text" placeholder="Enter your name" required />
        </div>
        <div className="cf-field sm:pl-4">
          <label htmlFor="cf-email">Email Address</label>
          <input id="cf-email" type="email" placeholder="Enter your email" required />
        </div>
      </div>
      <div className="cf-field">
        <label htmlFor="cf-subject">Subject</label>
        <input id="cf-subject" type="text" placeholder="How can we help?" />
      </div>
      <div className="cf-field">
        <label htmlFor="cf-phone">Phone Number</label>
        <input id="cf-phone" type="tel" placeholder="+1 (000) 000-0000" />
      </div>
      <div className="cf-field">
        <label htmlFor="cf-msg">Message</label>
        <textarea id="cf-msg" placeholder="Write your message here..." required />
      </div>
      <button type="submit" className="btn btn-fancy-primary btn-lg w-full sm:w-auto">
        {sent ? "Message Sent ✓" : "Send Message"}
      </button>
    </form>
  );
}
