"use client";
// Mirrors React-template TestimonialsCarousel.jsx — style-01 to 07

import { useCallback, useEffect, useState } from "react";
import type { TestimonialItem } from "./Testimonials";

interface Props {
  theme?: "testimonials-carousel-style-01" | "testimonials-carousel-style-02" | "testimonials-carousel-style-03" |
          "testimonials-carousel-style-04" | "testimonials-carousel-style-05" | "testimonials-carousel-style-06" |
          "testimonials-carousel-style-07";
  data: TestimonialItem[];
  autoPlay?: boolean;
}

function Stars({ n }: { n: number }) {
  return <span>{"★".repeat(n)}{"☆".repeat(5 - n)}</span>;
}

export default function TestimonialsCarousel({ theme = "testimonials-carousel-style-01", data, autoPlay = true }: Props) {
  const [active, setActive] = useState(0);
  const total = data.length;
  const next = useCallback(() => setActive((p) => (p + 1) % total), [total]);
  const prev = () => setActive((p) => (p - 1 + total) % total);

  useEffect(() => {
    if (!autoPlay) return;
    const id = setInterval(next, 5000);
    return () => clearInterval(id);
  }, [autoPlay, next]);

  const dark = theme === "testimonials-carousel-style-06" || theme === "testimonials-carousel-style-07";

  /* Determine card class based on theme */
  const cardCls =
    theme === "testimonials-carousel-style-02" ? "testi-02" :
    theme === "testimonials-carousel-style-03" ? "testi-03" :
    theme === "testimonials-carousel-style-04" ? "testi-04" :
    theme === "testimonials-carousel-style-05" ? "testi-05" :
    "testi-01";

  return (
    <div className={dark ? "tc-dark" : ""}>
      <div className="carousel-track-wrap">
        <div className="carousel-track" style={{ transform: `translateX(-${active * 100}%)` }}>
          {data.map((item, i) => (
            <div key={i} className="carousel-slide" style={{ width: "100%", padding: "0 0.5rem" }}>
              <Card item={item} cls={cardCls} />
            </div>
          ))}
        </div>
      </div>

      <div className="slider-nav">
        <button className="slider-prev" onClick={prev} aria-label="Previous">←</button>
        {data.map((_, i) => (
          <button
            key={i}
            className={`slider-dot ${i === active ? "active" : ""}`}
            onClick={() => setActive(i)}
            aria-label={`Slide ${i + 1}`}
          />
        ))}
        <button className="slider-next" onClick={next} aria-label="Next">→</button>
      </div>
    </div>
  );
}

function Card({ item, cls }: { item: TestimonialItem; cls: string }) {
  if (cls === "testi-02") {
    return (
      <div className="testi-02">
        {item.img && <img src={item.img} alt={item.name} />}
        <div>
          <p className="t-content">"{item.content}"</p>
          <div className="t-name">{item.name}</div>
          {item.designation && <div className="t-role">{item.designation}</div>}
        </div>
      </div>
    );
  }
  if (cls === "testi-04") {
    return (
      <div className="testi-04">
        <div className="t-stars"><Stars n={item.rating || 5} /></div>
        <p className="t-content">"{item.content}"</p>
        <div className="t-author">
          {item.img && <img src={item.img} alt={item.name} />}
          <div>
            <div className="t-name">{item.name}</div>
            {item.designation && <div className="t-role">{item.designation}</div>}
          </div>
        </div>
      </div>
    );
  }
  // default testi-01, testi-03, testi-05
  return (
    <div className={cls}>
      {cls === "testi-01" && <div className="t-quote">"</div>}
      {(cls === "testi-04" || cls === "testi-05") && item.rating && <div className="t-stars"><Stars n={item.rating} /></div>}
      <p className="t-content">"{item.content}"</p>
      <div className="t-author">
        {item.img && <img src={item.img} alt={item.name} />}
        <div>
          <div className="t-name">{item.name}</div>
          {item.designation && <div className="t-role">{item.designation}</div>}
        </div>
      </div>
    </div>
  );
}
