"use client";

import { useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";

const NAV = [
  { label: "Modules",  href: "/features" },
  { label: "Pricing",  href: "/pricing" },
  { label: "About Us", href: "/about" },
  { label: "Contact",  href: "/contact" },
];

export default function HeaderCentered() {
  const [menuOpen, setMenuOpen] = useState(false);
  const pathname = usePathname();

  return (
    <header className="bg-white border-b border-[--border] w-full z-50">
      {/* Top row: centered logo */}
      <div className="container-xl flex items-center justify-center py-4 border-b border-[--border]">
        <Link href="/" className="flex items-center gap-2">
          <svg width="28" height="28" viewBox="0 0 32 32" fill="none">
            <circle cx="16" cy="16" r="13" stroke="var(--primary)" strokeWidth="2" fill="none" />
            <ellipse cx="16" cy="16" rx="7" ry="13" stroke="var(--primary)" strokeWidth="1.5" fill="none" />
            <line x1="3" y1="16" x2="29" y2="16" stroke="var(--primary)" strokeWidth="1.5" />
          </svg>
          <span className="text-[20px] font-bold tracking-tight text-[--dark]">
            Sync<span className="text-[--primary]">Core</span>
          </span>
        </Link>
      </div>

      {/* Bottom row: centered nav */}
      <div className="hidden md:block">
        <div className="container-xl flex items-center justify-center gap-10 h-12">
          {NAV.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className={`text-xs font-semibold tracking-[.08em] uppercase transition-colors hover:text-[--primary] border-b-2 pb-[2px] ${
                pathname === link.href
                  ? "text-[--primary] border-[--primary]"
                  : "text-[--dark] border-transparent"
              }`}
            >
              {link.label}
            </Link>
          ))}
          <Link
            href="/contact"
            className="btn btn-sm btn-primary ml-4"
          >
            Request a Demo
          </Link>
        </div>
      </div>

      {/* Mobile burger */}
      <div className="md:hidden container-xl flex items-center justify-between h-12">
        <span className="text-xs text-[--text-light]">Navigation</span>
        <button
          onClick={() => setMenuOpen(!menuOpen)}
          className="flex flex-col gap-[5px] w-5 cursor-pointer"
          aria-label="Toggle menu"
        >
          {[0, 1, 2].map((i) => (
            <span
              key={i}
              className={`block h-[2px] bg-[--dark] rounded transition-all duration-300
                ${i === 0 && menuOpen ? "rotate-45 translate-y-[7px]" : ""}
                ${i === 1 && menuOpen ? "opacity-0 scale-x-0" : ""}
                ${i === 2 && menuOpen ? "-rotate-45 -translate-y-[7px]" : ""}`}
            />
          ))}
        </button>
      </div>

      {menuOpen && (
        <div className="md:hidden border-t border-[--border] bg-white">
          <div className="container-xl py-3 flex flex-col gap-0.5">
            {NAV.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                onClick={() => setMenuOpen(false)}
                className="py-2.5 px-3 text-sm font-medium text-[--dark] hover:text-[--primary] hover:bg-[--primary]/5 rounded transition-colors"
              >
                {link.label}
              </Link>
            ))}
          </div>
        </div>
      )}
    </header>
  );
}
