"use client";
// Mirrors React-template Subscribe.jsx — subscribe-style-01 to 05

interface Props {
  theme?: "subscribe-style-01" | "subscribe-style-02" | "subscribe-style-03" | "subscribe-style-04" | "subscribe-style-05" | "subscribe-style-06" | "subscribe-style-07" | "subscribe-style-08" | "subscribe-style-09";
  placeholder?: string;
  btnLabel?: string;
}

export default function Subscribe({ theme = "subscribe-style-01", placeholder = "Enter your email address", btnLabel = "Subscribe" }: Props) {
  const n = theme.replace("subscribe-style-0", "");
  const cls = `sub-0${n}`;

  return (
    <div className={cls}>
      <form className="sub-form" onSubmit={(e) => e.preventDefault()}>
        <input type="email" className="sub-input" placeholder={placeholder} required />
        <button type="submit" className="sub-btn">{btnLabel}</button>
      </form>
    </div>
  );
}
